#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long n = X - Y;
        long long ans = (n == 0) ? (2*Y - 1) : (2*Y + n);
        printf("%lld", ans);
        if(T) printf("\n");
    }
    return 0;
}

